import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"啟動遊戲","description":"了解如何利用各種啟動設定檔在即時遊戲環境中啟動和除錯您的模組。","frontmatter":{"title":"啟動遊戲","description":"了解如何利用各種啟動設定檔在即時遊戲環境中啟動和除錯您的模組。","authors":["IMB11","Tenneb22"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.4/develop/getting-started/launching-the-game.md","filePath":"versions/1.21.4/translated/zh_tw/develop/getting-started/launching-the-game.md","lastUpdated":1760721669000}`);var c={name:`zh_tw/1.21.4/develop/getting-started/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">啟動遊戲 <a class="header-anchor" href="#h1" aria-label="Permalink to “啟動遊戲”">​</a></h1><p>Fabric Loom 提供多種啟動配置檔案，幫助你在實時遊戲環境中啟動模組並進行除錯。 本指南將介紹各種啟動配置檔案以及如何用它們來除錯及在遊戲中測試你的模組。</p><h2 id="launch-profiles" tabindex="-1">啟動配置檔案 <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “啟動配置檔案”">​</a></h2><p>如果你使用的是 IntelliJ IDEA，你可以在視窗的右上角找到啟動配置檔案。 點擊下拉選單可以查看可用的啟動配置檔案。</p><p>應該有一個客戶端和伺服器端配置檔案，可以選擇正常執行或在除錯模式下執行它:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="啟動配置" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Gradle 任務 <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Gradle 任務”">​</a></h2><p>如果你使用的是命令行，則可以使用以下 Gradle 指令啟動遊戲：</p><ul><li><code>./gradlew runClient</code> - 以用戶端啟動遊戲。</li><li><code>./gradlew runServer</code> - 以伺服器端啟動遊戲。</li></ul><p>這種方法的唯一問題是無法輕鬆為程式碼除錯。 如果想要進行程式碼除錯，你需要使用 IntelliJ IDEA 中的啟動配置檔案，或者通過你的 IDE 的 Gradle 集成來進行。</p><h2 id="hotswapping-classes" tabindex="-1">熱插拔類別 <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “熱插拔類別”">​</a></h2><p>在除錯模式下運行遊戲時，可以熱插拔你的類別而無需重啟遊戲。 這對於快速測試程式碼的更改很有用。</p><p>但依舊會受到很大的限制：</p><ul><li>無法新增或刪除方法</li><li>無法修改方法參數</li><li>無法添加或刪除欄位</li></ul><p>不過，使用 <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">JetBrains Runtime</a> ，你就可以避開大多數的限制，甚至可以增加或移除類別的方法。 這應該能夠讓大多數變更在不重新啟動遊戲的情況下生效。</p><p>不要忘記在你的 Minecraft 運行配置中的 VM Arguments 選項中新增以下內容：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">熱插拔 Mixins <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “熱插拔 Mixins”">​</a></h2><p>如果你正在使用 Mixin，則可以熱插拔 Mixin 類別而無須重啟遊戲。 這對於快速測試 Mixin 的更改很有用。</p><p>但是需要安裝 Mixin Java 代理才能正常運作。</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. 找到 Mixin 程式庫 Jar <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. 找到 Mixin 程式庫 Jar”">​</a></h3><p>在 IntelliJ IDEA中，你可以在「Project」部分的「External Libraries」部分找到 mixin 程式庫：</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Mixin Library" loading="lazy"></p><p>你需要複製 Jar 的「絕對路徑」以供下一步使用。</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. 加入 <code>-javaagent</code> VM 參數 <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. 加入 -javaagent VM 參數”">​</a></h3><p>在你的「Minecraft Client」和/或「Minecraft Server」啟動配置中，將以下內容加進 VM 參數選項：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent: 「mixin 程式庫 Jar 的路徑」</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="VM 參數截圖" loading="lazy"></p><p>現在，你應該能夠在除錯期間修改 mixin 方法的內容，並且無須重啟遊戲即可使修改生效。</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};